  subConfig: SubscriptionConfig;
  onUpdateConfig: (cfg: SubscriptionConfig) => void;
  onPaySubscription: (subId: string, paymentMethod: 'CASH' | 'UPI' | 'ONLINE' | 'CARD' | 'NET_BANKING', amount: number) => void;
